import{_ as l,c as i,o as e,a4 as a}from"./chunks/framework.HaEZziQ1.js";const m=JSON.parse('{"title":"源码原理解析学习指导","description":"","frontmatter":{},"headers":[],"relativePath":"Document/框架源码原理实现解析/源码原理解析学习指导.md","filePath":"Document/框架源码原理实现解析/源码原理解析学习指导.md","lastUpdated":1709668918000}'),t={name:"Document/框架源码原理实现解析/源码原理解析学习指导.md"},r=a('<h1 id="源码原理解析学习指导" tabindex="-1">源码原理解析学习指导 <a class="header-anchor" href="#源码原理解析学习指导" aria-label="Permalink to &quot;源码原理解析学习指导&quot;">​</a></h1><h2 id="为什么要学习源码和底层原理" tabindex="-1">为什么要学习源码和底层原理 <a class="header-anchor" href="#为什么要学习源码和底层原理" aria-label="Permalink to &quot;为什么要学习源码和底层原理&quot;">​</a></h2><ol><li>面试需要</li><li>架构师 资深前端 <ol><li>做一些更高端和通用的事情</li><li>组件化，框架</li><li>框架源码里，有大量的最佳实践</li><li>vue 源码里，大量的工程化，设计模式，代码规范的最佳实践</li></ol></li><li>资深前端 <ol><li>除了经验丰富外</li><li>视野更高</li><li>解决诡异的 bug</li><li>架构的设计</li></ol></li></ol><h2 id="刻意练习" tabindex="-1">刻意练习 <a class="header-anchor" href="#刻意练习" aria-label="Permalink to &quot;刻意练习&quot;">​</a></h2><p>学习一个技能的最好途径，就是刻意练习，天天下象棋的村头王大爷，一定是个臭棋篓子，我天天玩王者荣耀，也是个钻石的菜比 武林高手不是天天打架就可以的，需要练习，需要专门修炼内力，以打 dota 为例</p><ol><li>任务分解 <ol><li>补刀(不带装备中路正反补 10 分钟)</li><li>装备</li><li>英雄搭配</li><li>兵线</li><li>手速 2.练习</li><li>很枯燥，自找不痛快（补刀毫无游戏乐趣）</li><li>完整的实践修炼</li></ol></li><li>反馈 4. 高手的源码 （vuejs 源码） 5. 高手点评</li></ol><h2 id="源码学习方法" tabindex="-1">源码学习方法 <a class="header-anchor" href="#源码学习方法" aria-label="Permalink to &quot;源码学习方法&quot;">​</a></h2><p>我认为源码学习分为三个层次 0. 根据 package.json 的 npm run build 逻辑找到 vue 执行的入口</p><ol><li>看一遍整体结构，比如把所有函数都折叠起来 看整体逻辑</li><li>参考测试代码，该清楚每个具体函数的输入输出，看明白逻辑</li><li>核心逻辑手写一遍 （虚拟 dom，compile，响应式等）</li><li>组内立 flag 分享，吹牛逼一次</li></ol><h2 id="如何熟读源码和手写实现" tabindex="-1">如何熟读源码和手写实现 <a class="header-anchor" href="#如何熟读源码和手写实现" aria-label="Permalink to &quot;如何熟读源码和手写实现&quot;">​</a></h2><p><a href="https://juejin.cn/post/7126095681428668424" target="_blank" rel="noreferrer">https://juejin.cn/post/7126095681428668424</a></p><h3 id="_1-找文档" tabindex="-1">1.找文档 <a class="header-anchor" href="#_1-找文档" aria-label="Permalink to &quot;1.找文档&quot;">​</a></h3><ul><li>1.官方文档 <ul><li>一般官方文档更全面更丰富，维护度也更高</li></ul></li><li>2.源码版本号很重要，不少源码随着版本迭代，发生了破坏性改动，不同版本对应的文档也不同，比如 react-router5 与 react-router6，因此看文档的时候，一定检查下你看的文档版本号和你要学习使用的源码是否一致。</li><li>3.关于文档版本号，一般可以在路由地址上或者官网首页上看到，之后再去看下 github 源码对应的版本号，确保两者一致。</li><li>4.如果找不到官方文档，可以先去 github 源码看一下，README 里通常是一份简单的文档，有些还是中英文都有的:</li><li>5.这个时候如果有官方文档，README 里会有链接指引。如果没有的话，可以查看下源码里是否有一个叫 docs 的文件夹： <ul><li>一般成熟的源码里都会有这个文件夹，里面就是文档。甚至有些源码下的 docs 比官方文档都全面。</li></ul></li><li>6.现在很多源码项目都是基于 monorepo 开发的，很多 packages 下的文件也都是独立的，看文档的时候，建议不要放过 docs 与 README。</li></ul><h3 id="_2-github-看示例代码与单元测试-测试用例" tabindex="-1">2.github 看示例代码与单元测试|测试用例 <a class="header-anchor" href="#_2-github-看示例代码与单元测试-测试用例" aria-label="Permalink to &quot;2.github 看示例代码与单元测试|测试用例&quot;">​</a></h3><ul><li>经历了文档阶段之后，再根据文档写一些 demo，相信大家对于这套源码已经掌握了至少六七分了，那么接下来想要在某一个难点上继续学习的话，可以看看别人的逻辑，比如示例代码和单元测试。</li><li>1.示例代码通常在 examples 文件夹下</li><li>2.单元测试是验证源码逻辑的代码，如果你对某个 API 用法不确定准确逻辑，可以去看看单元测试代码或者调试下试试 <ul><li>一般在 test 关键字的文件夹下</li></ul></li></ul><h3 id="_3-1-浏览器-github-插件实时看源码" tabindex="-1">3.1 浏览器 github 插件实时看源码 <a class="header-anchor" href="#_3-1-浏览器-github-插件实时看源码" aria-label="Permalink to &quot;3.1 浏览器 github 插件实时看源码&quot;">​</a></h3><h3 id="_3-2-编辑器阅读源码" tabindex="-1">3.2 编辑器阅读源码 <a class="header-anchor" href="#_3-2-编辑器阅读源码" aria-label="Permalink to &quot;3.2 编辑器阅读源码&quot;">​</a></h3><ul><li><ol><li>下载库源码文件</li></ol><ul><li><ol><li>直接下载或者 clone 克隆项目到本地</li></ol></li><li>2 CDN 或 npm 下载编译好的库源码 <ul><li>CDN <ul><li>bootcdn <ul><li><a href="https://www.bootcdn.cn/" target="_blank" rel="noreferrer">https://www.bootcdn.cn/</a></li></ul></li><li>Staticfile <ul><li><a href="https://staticfile.org/" target="_blank" rel="noreferrer">https://staticfile.org/</a></li></ul></li><li>75CDN <ul><li><a href="https://cdn.baomitu.com/" target="_blank" rel="noreferrer">https://cdn.baomitu.com/</a></li></ul></li><li>今日头条 CDN <ul><li><a href="https://cdn.bytedance.com/" target="_blank" rel="noreferrer">https://cdn.bytedance.com/</a></li></ul></li><li>cdnjs <ul><li><a href="https://cdnjs.com/" target="_blank" rel="noreferrer">https://cdnjs.com/</a></li></ul></li><li>jsDelivr <ul><li><a href="https://www.jsdelivr.com/" target="_blank" rel="noreferrer">https://www.jsdelivr.com/</a></li></ul></li></ul></li><li>npm <ul><li><a href="https://www.npmjs.com/" target="_blank" rel="noreferrer">https://www.npmjs.com/</a></li><li>npm 上可以看到 github 地址和主页</li></ul></li></ul></li></ul></li><li><ol start="2"><li>vscode 工具安装插件辅助阅读</li></ol><ul><li>要下载或者拉取源码来看看了，但是一般源码的代码量比较大，没法一次看完，所以我们可以借助一些工具来辅助阅读，vscode 上建议安装 Bookmarks、Better Comments、Git Blame 等插件。</li><li>Bookmarks <ul><li>可以打一些书签，方便记忆，下次可以快速找到某个函数或值。</li></ul></li><li>Better Comments <ul><li>可以做些颜色笔记，看起来比较醒目</li></ul></li><li>Git Blame <ul><li>则可以帮助查看源码的提交记录，注意得是远程拉取下来的代码，直接下载的不可以查看</li></ul></li></ul></li></ul><h3 id="_4-源码阅读" tabindex="-1">4.源码阅读 <a class="header-anchor" href="#_4-源码阅读" aria-label="Permalink to &quot;4.源码阅读&quot;">​</a></h3><ul><li>1.首先，我们要先区分下不同的文件夹下放的都是什么，并不是每个都要去看的 <ul><li>先看文件夹命名，命名和框架名称一致的或者叫 core、model 的基本都是核心文件</li></ul></li><li>2.文件目录下直接搜索关键字 <ul><li>比如我想看 createForm 的实现逻辑，直接搜索关键字</li></ul></li><li>3.自己思考功能的实现方式 <ul><li>不了解功能就开始读源码，那读代码会没有方向感</li><li>知道了源码有啥功能之后，要先思考下如果自己实现会怎么做。有个大概的思路就行。</li><li>如果想不通可以看下源码用到了哪些依赖库，这些依赖库都有啥功能，再想下应该怎么实现。</li><li>如果还想不通也没关系，重要的是要先自己思考下实现方式。</li></ul></li><li>4.粗读源码理清实现思路 <ul><li>你已经有了一个大概的实现思路，然后再去读源码，看下它是怎么实现的。和你思路类似的地方很快就可以掠过去，而且印象也很深，和你思路不一样的地方，通过读代码搞清楚它的实现思路。</li><li>这一步不用关心细节，知道某段代码是干啥的就行，关键是和自己的思路做 diff，理清它的整体实现思路。</li><li>不经过思考直接读源码，理解代码实现思路的效率会降低</li></ul></li><li>5.快速调试代码</li><li>5.通过 debugger 理清实现细节 <ul><li>不理清整体思路就开始 debugger，会容易陷入细节，理不清整体的思路</li><li>粗读源码理清了实现思路之后，对于一些部分的具体实现可能还不是很清楚，这时候就可以通过 debugger 来断点调试了。</li><li>构造一个能触发该功能的测试用例，在关心的代码处打一个断点，通过 debugger 运行代码。</li><li>这时候你已经知道这部分代码是干啥的了，单步调试也很容易理清每一条语句的功能，这样一条语句一条语句的搞懂之后，你就很容易能把这部分代码的实现细节理清楚。</li><li>这样一部分一部分的通过 debugger 理清细节实现之后，你就对整体代码的思路和细节的实现都有了比较好的掌握。</li><li>不 debugger 只大概理下整体思路，这样不能从细节上真正理清楚</li></ul></li><li>6.输出文章来讲述源码实现思路 <ul><li>当你觉得对源码的实现有了比较好的掌握的时候，可以输出一篇文章的方式来讲述源码的整体思路。</li><li>因为可能会有一些部分是你没注意到的，而在输出的过程中，会进行更全面的思考，这时候如果发现了一些没有读到的点，可以再通过前面几步去阅读源码，直到能清晰易懂的把源码的实现讲清楚。这样才算真正的把代码读懂了。</li><li>这就是我觉得比较高效的阅读源码的方法。</li><li>不通过输出文章来检验，那是否真的理清了整体思路和实现细节是没底的</li></ul></li><li>vue 和 react 源码阅读：<a href="https://juejin.cn/post/6903335881227108366" target="_blank" rel="noreferrer">https://juejin.cn/post/6903335881227108366</a></li></ul><h3 id="_5-手写实现" tabindex="-1">5.手写实现 <a class="header-anchor" href="#_5-手写实现" aria-label="Permalink to &quot;5.手写实现&quot;">​</a></h3><ul><li>读万卷书不如行万里路，动手写一遍</li><li>手写我通常是一步步实现，比如先写个最简单的 demo，然后把 api 全部换掉，导入换成自己手写的文件，然后再挨个实现，一边看源码，一边整理思路，直到呈现和源码一样的实现。</li><li>手写我通常是一步步实现，比如先写个最简单的 demo，然后把 api 全部换掉，换成自己手写的，然后再挨个实现，一边看源码，一边整理思路，直到呈现和源码一样的实现。</li></ul><h3 id="_6-github-issues" tabindex="-1">6.github issues <a class="header-anchor" href="#_6-github-issues" aria-label="Permalink to &quot;6.github issues&quot;">​</a></h3><ul><li>如果你发现看文档和源码的过程中，有很多困惑，甚至遇到一些 bug，可以去 issues 看看，看看大家的发言，也许就能找到答案。</li></ul><h3 id="_7-加社区群-关注核心维护者" tabindex="-1">7.加社区群，关注核心维护者 <a class="header-anchor" href="#_7-加社区群-关注核心维护者" aria-label="Permalink to &quot;7.加社区群，关注核心维护者&quot;">​</a></h3><p>文章：<a href="https://juejin.cn/column/6960551178908205093" target="_blank" rel="noreferrer">学习源码整体架构系列 - 若川的专栏 - 掘金 (juejin.cn)</a></p>',26),o=[r];function u(n,h,s,c,d,b){return e(),i("div",null,o)}const p=l(t,[["render",u]]);export{m as __pageData,p as default};
